<span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">time</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Duration</span><span style="color:#9399B2;">;</span></span>
